export * from "./input-group";
export * as InputGroup from "./namespace";
export * from "./styles";

"use client";

import { mergeProps } from "@base-ui/react/merge-props";
import { useRender } from "@base-ui/react/use-render";
import type { VariantProps } from "cva";
import { composeRenderProps } from "react-aria-components";
import { Button } from "~/registry/ui/button";
import { Input } from "~/registry/ui/input";
import { Textarea } from "~/registry/ui/textarea";
import { InputGroupStyles } from "./styles";

export interface InputGroupRootProps extends useRender.ComponentProps<"div"> {}

export function InputGroupRoot({
  render,
  className,
  ...props
}: InputGroupRootProps) {
  const defaultProps: useRender.ElementProps<"div"> = {
    className: InputGroupStyles.Root({ className }),
    role: "group",
    ["data-slot" as string]: "input-group-root",
  };

  return useRender({
    defaultTagName: "div",
    render,
    props: mergeProps<"div">(defaultProps, props),
  });
}

export interface InputGroupAddonProps
  extends React.ComponentProps<"div">,
    VariantProps<typeof InputGroupStyles.Addon> {}

export function InputGroupAddon({
  className,
  align = "inline-start",
  ...props
}: InputGroupAddonProps) {
  return (
    // biome-ignore lint/a11y/noNoninteractiveElementInteractions: This is fine for this use case.
    // biome-ignore lint/a11y/useKeyWithClickEvents: This is fine for this use case.
    <div
      className={InputGroupStyles.Addon({ align, className })}
      data-align={align}
      data-slot="input-group-addon"
      onClick={(e) => {
        if ((e.target as HTMLElement).closest("button")) {
          return;
        }
        e.currentTarget.parentElement?.querySelector("input")?.focus();
      }}
      role="group"
      {...props}
    />
  );
}

export interface InputGroupButtonProps
  extends Omit<React.ComponentProps<typeof Button>, "size">,
    VariantProps<typeof InputGroupStyles.Button> {}

export function InputGroupButton({
  className,
  type = "button",
  variant = "ghost",
  size = "xs",
  ...props
}: InputGroupButtonProps) {
  return (
    <Button
      className={composeRenderProps(className, (className) =>
        InputGroupStyles.Button({ size, className })
      )}
      data-size={size}
      type={type}
      variant={variant}
      {...props}
    />
  );
}

export interface InputGroupTextProps extends React.ComponentProps<"span"> {}

export function InputGroupText({ className, ...props }: InputGroupTextProps) {
  return <span className={InputGroupStyles.Text({ className })} {...props} />;
}

export interface InputGroupInputProps
  extends React.ComponentProps<typeof Input> {}

export function InputGroupInput({ className, ...props }: InputGroupInputProps) {
  return (
    <Input
      className={composeRenderProps(className, (className) =>
        InputGroupStyles.Input({ className })
      )}
      data-slot="input-group-control"
      {...props}
    />
  );
}

export interface InputGroupTextareaProps
  extends React.ComponentProps<typeof Textarea> {}

export function InputGroupTextarea({
  className,
  ...props
}: InputGroupTextareaProps) {
  return (
    <Textarea
      className={composeRenderProps(className, (className) =>
        InputGroupStyles.Textarea({ className })
      )}
      data-slot="input-group-control"
      {...props}
    />
  );
}

export {
  InputGroupAddon as Addon,
  InputGroupButton as Button,
  InputGroupInput as Input,
  InputGroupRoot as Root,
  InputGroupText as Text,
  InputGroupTextarea as Textarea,
} from "./input-group";

import { cva } from "~/registry/lib/cva";

export const InputGroupStyles = {
  Root: cva({
    base: [
      "group/input-group relative flex w-full items-center rounded-md border border-input shadow-xs outline-none transition-[color,box-shadow] dark:bg-input/30",
      "h-9 min-w-0 has-[>textarea]:h-auto",

      // Variants based on alignment.
      "has-[>[data-align=inline-start]]:[&>input]:pl-2",
      "has-[>[data-align=inline-end]]:[&>input]:pr-2",
      "has-[>[data-align=block-start]]:h-auto has-[>[data-align=block-start]]:flex-col has-[>[data-align=block-start]]:[&>input]:pb-3",
      "has-[>[data-align=block-end]]:h-auto has-[>[data-align=block-end]]:flex-col has-[>[data-align=block-end]]:[&>input]:pt-3",

      // Focus state.
      "has-[[data-slot=input-group-control]:focus-visible]:border-ring has-[[data-slot=input-group-control]:focus-visible]:ring-[3px] has-[[data-slot=input-group-control]:focus-visible]:ring-ring/50",

      // Error state.
      "has-[[data-slot][aria-invalid=true]]:border-destructive has-[[data-slot][aria-invalid=true]]:ring-destructive/20 dark:has-[[data-slot][aria-invalid=true]]:ring-destructive/40",
    ],
  }),
  Addon: cva({
    base: "flex h-auto cursor-text select-none items-center justify-center gap-2 py-1.5 font-medium text-muted-foreground text-sm group-data-[disabled=true]/input-group:opacity-50 [&>kbd]:rounded-[calc(var(--radius)-5px)] [&>svg:not([class*='size-'])]:size-4",
    variants: {
      align: {
        "inline-start":
          "order-first pl-3 has-[>button]:ml-[-0.45rem] has-[>kbd]:ml-[-0.35rem]",
        "inline-end":
          "order-last pr-3 has-[>button]:mr-[-0.45rem] has-[>kbd]:mr-[-0.35rem]",
        "block-start":
          "order-first w-full justify-start px-3 pt-3 group-has-[>input]/input-group:pt-2.5 [.border-b]:pb-3",
        "block-end":
          "order-last w-full justify-start px-3 pb-3 group-has-[>input]/input-group:pb-2.5 [.border-t]:pt-3",
      },
    },
    defaultVariants: {
      align: "inline-start",
    },
  }),
  Button: cva({
    base: "flex items-center gap-2 text-sm shadow-none",
    variants: {
      size: {
        xs: "h-6 gap-1 rounded-[calc(var(--radius)-5px)] px-2 has-[>svg]:px-2 [&>svg:not([class*='size-'])]:size-3.5",
        sm: "h-8 gap-1.5 rounded-md px-2.5 has-[>svg]:px-2.5",
        "icon-xs":
          "size-6 rounded-[calc(var(--radius)-5px)] p-0 has-[>svg]:p-0",
        "icon-sm": "size-8 p-0 has-[>svg]:p-0",
      },
    },
    defaultVariants: {
      size: "xs",
    },
  }),
  Text: cva({
    base: [
      "flex items-center gap-2 text-muted-foreground text-sm [&_svg:not([class*='size-'])]:size-4 [&_svg]:pointer-events-none",
    ],
  }),
  Input: cva({
    base: [
      "flex-1 rounded-none border-0 bg-transparent shadow-none focus:ring-0 dark:bg-transparent",
    ],
  }),
  Textarea: cva({
    base: [
      "flex-1 resize-none rounded-none border-0 bg-transparent py-3 shadow-none focus:ring-0 dark:bg-transparent",
    ],
  }),
};
